(() => {
  const query = new URLSearchParams(window.location.search).get("q");
  if (!query || !query.trim() || query.trim().length < 2) return;

  const rawQuery = query.trim();
  const normalizedQuery = rawQuery.toLowerCase().replace(/\s+/g, " ").trim();
  const compactQuery = normalizedQuery.replace(/[^a-z0-9]+/g, "");
  const tokens = normalizedQuery.split(/\s+/).filter(Boolean);
  const isExactPartQuery = /^[a-z0-9]+(?:-[a-z0-9]+)+$/i.test(rawQuery);
  const broadJumpQueries = [
    "reading light",
    "reading lights",
    "led reading light",
    "led reading lights"
  ];

  function normalizeText(value) {
    return String(value || "").toLowerCase().replace(/\s+/g, " ").trim();
  }

  function compactText(value) {
    return normalizeText(value).replace(/[^a-z0-9]+/g, "");
  }

  function injectStyles() {
    if (document.getElementById("search-jump-styles")) return;
    const style = document.createElement("style");
    style.id = "search-jump-styles";
    style.textContent = `
      .search-jump-hit {
        animation: search-jump-pulse 1.8s ease-out 1;
        scroll-margin-top: 110px;
      }
      .search-jump-hit > td,
      .search-jump-hit > th {
        background: rgba(0, 0, 0, 0.03) !important;
      }
      .search-jump-hit:not(tr) {
        background: rgba(0, 0, 0, 0.03) !important;
        border-radius: 0.5rem;
      }
      @keyframes search-jump-pulse {
        0% { opacity: 0.65; }
        100% { opacity: 1; }
      }
    `;
    document.head.appendChild(style);
  }

  function openAncestorDetails(element) {
    let current = element;
    while (current) {
      if (current.tagName === "DETAILS" && !current.classList.contains("model-card")) current.open = true;
      current = current.parentElement;
    }
  }

  function getTargetElement(element) {
    if (!element) return null;
    return (
      element.closest("tr") ||
      element.closest("details") ||
      element.closest("li") ||
      element
    );
  }

  function scoreElement(element) {
    const text = normalizeText(element.textContent || "");
    if (!text || text.length < 2) return -1;

    const compact = compactText(text);
    let score = -1;

    if (compactQuery && compact.includes(compactQuery)) score += 90;
    if (normalizedQuery && text.includes(normalizedQuery)) score += 120;
    if (tokens.length && tokens.every((token) => text.includes(token))) score += 45;
    if (score < 0) return -1;

    const tag = element.tagName;
    if (tag === "TR") score += 45;
    else if (tag === "TD" || tag === "TH") score += 35;
    else if (tag === "DETAILS") score += 32;
    else if (tag === "LI") score += 22;
    else if (/^H[1-4]$/.test(tag)) score += 18;
    else if (tag === "P") score += 12;

    if (element.classList.contains("pn")) score += 55;
    if (element.hasAttribute("data-label")) score += 12;
    if (element.closest("#search-grid")) score += 80;
    if (element.closest("#searchResults")) score += 80;
    if (element.closest("#product-accordion")) score += 44;
    if (element.closest("table")) score += 28;
    if (element.closest(".overflow-x-auto")) score += 12;
    if (element.closest("main > section:first-child")) score -= 70;
    if (element.closest("form")) score -= 80;
    if (element.tagName === "INPUT" || element.tagName === "LABEL") score -= 90;
    // Penalize elements inside "Also Available" / cross-sell sections
    const parentSection = element.closest("section");
    if (parentSection) {
      const label = parentSection.querySelector("p");
      if (label && /also available/i.test(label.textContent)) score -= 200;
    }

    if (isExactPartQuery && compactQuery) {
      const exactCompactMatch = compact === compactQuery;
      const exactTextMatch = text === normalizedQuery;
      const row = element.closest("tr");
      const rowCompact = row ? compactText(row.textContent || "") : "";
      const rowHasExact = rowCompact.indexOf(compactQuery) !== -1;

      if (exactCompactMatch || exactTextMatch) score += 160;
      if ((element.tagName === "TD" || element.tagName === "TH") && rowHasExact) score += 130;
      if (element.classList.contains("pn") && rowHasExact) score += 180;
      if (row && rowHasExact) score += 110;
      if (element.closest("table") && rowHasExact) score += 75;
    }

    const lengthPenalty = Math.min(text.length / 220, 18);
    return score - lengthPenalty;
  }

  function findBestMatch() {
    const main = document.querySelector("main") || document.body;
    const selector = [
      "tr",
      "td",
      "th",
      "details",
      "li",
      "p",
      "h1",
      "h2",
      "h3",
      "h4",
      ".pn",
      "[data-label]",
      ".rowlike"
    ].join(",");

    const elements = Array.from(main.querySelectorAll(selector));
    let best = null;
    let bestScore = -1;

    elements.forEach((element) => {
      const score = scoreElement(element);
      if (score > bestScore) {
        bestScore = score;
        best = element;
      }
    });

    return bestScore >= 0 ? best : null;
  }

  function scrollToMatch(target) {
    const header = document.querySelector(".site-header");
    const headerOffset = header ? header.getBoundingClientRect().height + 20 : 96;
    const top = target.getBoundingClientRect().top + window.scrollY - headerOffset;
    window.scrollTo({ top: Math.max(top, 0), behavior: "smooth" });
  }

  function runSearchJump() {
    // Never jump on the search results page itself
    if (/\/search\.html/.test(window.location.pathname)) return;
    if (broadJumpQueries.includes(normalizedQuery)) return;
    if (document.querySelector(".model-card")) return;
    // If the page's h1 already covers the entire query, the whole page is the answer — skip jump
    const h1 = document.querySelector("h1");
    if (h1) {
      const h1Text = h1.textContent.toLowerCase();
      const tokens = rawQuery.toLowerCase().trim().split(/\s+/).filter(t => t.length >= 2);
      if (tokens.length && tokens.every(t => h1Text.includes(t) || h1Text.includes(t.replace(/s$/, '')))) return;
    }
    injectStyles();
    const match = findBestMatch();
    if (!match) return;

    openAncestorDetails(match);

    const target = getTargetElement(match);
    if (!target) return;

    requestAnimationFrame(() => {
      const canHighlight = /^(TR|TD|TH)$/.test(target.tagName);
      if (canHighlight) target.classList.add("search-jump-hit");
      scrollToMatch(target);
      if (canHighlight && typeof target.focus === "function") {
        if (!target.hasAttribute("tabindex")) target.setAttribute("tabindex", "-1");
        target.focus({ preventScroll: true });
      }
      if (canHighlight) window.setTimeout(() => target.classList.remove("search-jump-hit"), 1600);
    });
  }

  if (document.readyState === "loading") {
    document.addEventListener("DOMContentLoaded", () => {
      window.setTimeout(runSearchJump, 180);
    }, { once: true });
  } else {
    window.setTimeout(runSearchJump, 180);
  }
})();

// ── Language Picker + Google Translate ─────────────────────────────────────
(() => {
  const LANGS = [
    { code: 'en',    label: 'EN', name: 'English'   },
    { code: 'es',    label: 'ES', name: 'Español'   },
    { code: 'fr',    label: 'FR', name: 'Français'  },
    { code: 'de',    label: 'DE', name: 'Deutsch'   },
    { code: 'pt',    label: 'PT', name: 'Português' },
    { code: 'zh-CN', label: 'ZH', name: '中文'      },
  ];

  // Suppress Google Translate banner & body offset
  const gtStyle = document.createElement('style');
  gtStyle.textContent = '.goog-te-banner-frame,.skiptranslate{display:none!important}body{top:0!important}.goog-te-combo{display:none!important}.footer-cols>div{overflow-wrap:break-word;word-break:break-word;min-width:0}';
  document.head.appendChild(gtStyle);

  // Hidden GT element
  const gtEl = document.createElement('div');
  gtEl.id = 'pwi-gt-el';
  gtEl.style.cssText = 'position:absolute;left:-9999px;top:-9999px;visibility:hidden;overflow:hidden;height:0;width:0';
  document.body.appendChild(gtEl);

  // GT init callback
  window.googleTranslateElementInit = function () {
    new google.translate.TranslateElement({
      pageLanguage: 'en',
      includedLanguages: 'fr,de,es,ja,zh-CN,ar,pt,ko',
      autoDisplay: false
    }, 'pwi-gt-el');
  };

  let gtReady = false;
  let gtLoading = false;
  const gtWaiters = [];

  function markGtReady() {
    gtReady = true;
    gtLoading = false;
    gtWaiters.splice(0).forEach((fn) => fn());
  }

  function whenGtReady(fn) {
    if (gtReady) { fn(); return; }
    gtWaiters.push(fn);
  }

  function waitForGtCombo(fn, attempts) {
    if (document.querySelector('.goog-te-combo')) { fn(); return; }
    if (attempts <= 0) { fn(); return; }
    setTimeout(() => waitForGtCombo(fn, attempts - 1), 50);
  }

  function loadGoogleTranslate() {
    if (gtReady || gtLoading) return;
    gtLoading = true;
    const gtScript = document.createElement('script');
    gtScript.src = 'https://translate.google.com/translate_a/element.js?cb=googleTranslateElementInit';
    gtScript.onload = () => waitForGtCombo(() => markGtReady(), 80);
    gtScript.onerror = () => {
      gtLoading = false;
      fadeBody('in');
    };
    document.body.appendChild(gtScript);
  }

  // ── Helpers ─────────────────────────────────────────────────────────────
  function readCurrentLang() {
    const m = document.cookie.match(/googtrans=\/[a-z-]+\/([a-zA-Z-]+)/);
    return m ? m[1] : 'en';
  }

  function setLangCookies(code) {
    const host = location.hostname;
    const root = host.includes('.') ? '.' + host.split('.').slice(-2).join('.') : '';
    const expired = 'Thu, 01 Jan 1970 00:00:00 UTC';
    const clear = [
      `googtrans=;expires=${expired};path=/`,
      `googtrans=;expires=${expired};path=/;domain=${host}`,
    ];
    if (root) clear.push(`googtrans=;expires=${expired};path=/;domain=${root}`);
    clear.forEach((c) => { document.cookie = c; });
    if (code === 'en') return;
    const val = `/en/${code}`;
    const set = [
      `googtrans=${val};path=/`,
      `googtrans=${val};path=/;domain=${host}`,
    ];
    if (root) set.push(`googtrans=${val};path=/;domain=${root}`);
    set.forEach((c) => { document.cookie = c; });
  }

  function fadeBody(inOut) {
    document.body.style.transition = 'opacity 0.15s ease';
    document.body.style.opacity = inOut === 'out' ? '0' : '1';
  }

  function applyGtLang(code, onDone) {
    whenGtReady(() => {
      const sel = document.querySelector('.goog-te-combo');
      if (!sel) {
        setTimeout(() => applyGtLang(code, onDone), 250);
        return;
      }
      const done = () => { if (onDone) onDone(); };
      if (code === 'en') {
        sel.value = '';
        sel.dispatchEvent(new Event('change'));
        done();
        return;
      }
      fadeBody('out');
      setTimeout(() => {
        sel.value = code;
        sel.dispatchEvent(new Event('change'));
        setTimeout(() => { fadeBody('in'); done(); }, 350);
      }, 150);
    });
  }

  function switchLang(code) {
    const cur = readCurrentLang();
    if (code === cur) return;

    if (code === 'en') {
      fadeBody('out');
      setLangCookies('en');
      setTimeout(() => location.reload(), 150);
      return;
    }

    setLangCookies(code);
    loadGoogleTranslate();
    applyGtLang(code, () => markActiveLang(code));
  }

  // ── Build desktop dropdown items ─────────────────────────────────────────
  function buildDesktopDropdown(dd) {
    const inner = document.createElement('div');
    inner.style.cssText = 'padding:5px';
    LANGS.forEach(lang => {
      const btn = document.createElement('button');
      btn.type = 'button';
      btn.role = 'option';
      btn.dataset.pwiLang = lang.code;
      btn.dataset.pwiLabel = lang.label;
      btn.style.cssText = 'display:flex;align-items:center;gap:10px;width:100%;padding:7px 12px;background:none;border:none;color:#e2e8f0;font-size:0.8125rem;cursor:pointer;text-align:left;border-radius:0.375rem;transition:background 120ms;font-family:inherit';
      btn.innerHTML = `<span style="font-weight:700;font-size:0.6875rem;letter-spacing:0.08em;min-width:24px;color:#93c5fd">${lang.label}</span><span style="color:#94a3b8">${lang.name}</span>`;
      btn.addEventListener('mouseenter', () => { btn.style.background = 'rgba(255,255,255,0.09)'; });
      btn.addEventListener('mouseleave', () => { btn.style.background = 'none'; });
      inner.appendChild(btn);
    });
    dd.appendChild(inner);
  }

  // ── Build mobile lang grid ───────────────────────────────────────────────
  function buildMobileGrid(grid) {
    LANGS.forEach(lang => {
      const btn = document.createElement('button');
      btn.type = 'button';
      btn.dataset.pwiLang = lang.code;
      btn.dataset.pwiLabel = lang.label;
      btn.style.cssText = 'display:inline-flex;align-items:center;padding:5px 10px;border-radius:9999px;border:1px solid rgba(255,255,255,0.15);background:rgba(255,255,255,0.06);color:#e2e8f0;font-size:0.6875rem;font-weight:700;letter-spacing:0.08em;cursor:pointer;transition:background 120ms;font-family:inherit';
      btn.textContent = lang.label;
      btn.addEventListener('mouseenter', () => { btn.style.background = 'rgba(255,255,255,0.15)'; });
      btn.addEventListener('mouseleave', () => { btn.style.background = 'rgba(255,255,255,0.06)'; });
      grid.appendChild(btn);
    });
  }

  function markActiveLang(code) {
    document.querySelectorAll('[data-pwi-lang]').forEach((btn) => {
      const active = btn.dataset.pwiLang === code;
      btn.setAttribute('aria-pressed', active ? 'true' : 'false');
      if (btn.closest('#pwi-lang-mob-grid')) {
        btn.style.background = active ? 'rgba(59,95,224,0.35)' : 'rgba(255,255,255,0.06)';
        btn.style.borderColor = active ? 'rgba(124,157,247,0.55)' : 'rgba(255,255,255,0.15)';
        btn.style.color = active ? '#fff' : '#e2e8f0';
      }
    });
  }

  // ── Init picker ──────────────────────────────────────────────────────────
  function initPicker() {
    const btn     = document.getElementById('pwi-lang-btn');
    const dd      = document.getElementById('pwi-lang-dd');
    const lbl     = document.getElementById('pwi-lang-label');
    const chevron = document.getElementById('pwi-lang-chevron');
    const mobGrid = document.getElementById('pwi-lang-mob-grid');
    const mobSection = document.getElementById('pwi-lang-mob');
    const tabs = document.querySelector('.mnv2-tabs');

    let chip = null;
    let chipLabel = null;
    if (mobSection && tabs && tabs.parentElement) {
      tabs.parentElement.insertBefore(mobSection, tabs.nextSibling);
      tabs.style.order = '-2';
      mobSection.style.cssText = 'display:none;order:-1;margin:0 1.25rem 0.75rem;padding-top:0.85rem;border-top:1px solid rgba(148,163,184,0.12)';

      chip = document.createElement('button');
      chip.type = 'button';
      chip.id = 'pwi-lang-tab-chip';
      chip.setAttribute('aria-label', 'Select language');
      chip.setAttribute('aria-haspopup', 'true');
      chip.setAttribute('aria-expanded', 'false');
      chip.style.cssText = 'flex:0 0 auto;display:flex;align-items:center;justify-content:center;gap:3px;padding:0.5rem 0.45rem;border:0;border-radius:8px;background:transparent;color:rgba(203,213,225,0.75);font-family:inherit;font-size:0.68rem;font-weight:700;letter-spacing:0.03em;cursor:pointer;transition:background 160ms ease,color 160ms ease';
      chip.innerHTML = '<svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.75" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"><circle cx="12" cy="12" r="10"/><path d="M2 12h20M12 2a15.3 15.3 0 014 10 15.3 15.3 0 01-4 10 15.3 15.3 0 01-4-10 15.3 15.3 0 014-10z"/></svg><span id="pwi-lang-tab-label"></span>';
      tabs.appendChild(chip);
      chipLabel = chip.querySelector('#pwi-lang-tab-label');
    } else if (mobSection) {
      mobSection.style.display = 'block';
    }

    let mobOpen = false;
    let savedTab = null;
    const clearNavTabs = () => {
      document.querySelectorAll('.mnv2-tab.is-active').forEach(t => {
        t.classList.remove('is-active');
        t.setAttribute('aria-selected', 'false');
      });
      document.querySelectorAll('.mnv2-panel').forEach(p => { p.hidden = true; });
    };
    const restoreNavTab = () => {
      const tab = savedTab && document.contains(savedTab) ? savedTab : document.querySelector('.mnv2-tab');
      savedTab = null;
      if (tab) tab.click();
    };
    const openMob = () => {
      if (!mobSection || !chip) return;
      savedTab = document.querySelector('.mnv2-tab.is-active');
      clearNavTabs();
      mobSection.style.display = 'block';
      chip.setAttribute('aria-expanded', 'true');
      chip.classList.add('is-active');
      mobOpen = true;
    };
    const closeMob = (restoreTab = true) => {
      if (!mobSection || !chip) return;
      mobSection.style.display = 'none';
      chip.setAttribute('aria-expanded', 'false');
      chip.classList.remove('is-active');
      mobOpen = false;
      if (restoreTab) restoreNavTab();
      else savedTab = null;
    };
    window.PWI_MOB_LANG = { close: closeMob, isOpen: () => mobOpen };
    if (chip) {
      chip.addEventListener('click', e => { e.stopPropagation(); mobOpen ? closeMob() : openMob(); });
    }
    document.querySelectorAll('.mnv2-tab').forEach(tab => {
      tab.addEventListener('click', () => { if (mobOpen) closeMob(false); });
    });
    document.addEventListener('click', e => {
      if (mobOpen && mobSection && chip && !mobSection.contains(e.target) && !chip.contains(e.target)) closeMob();
    });

    const cur = readCurrentLang();
    const isSearchPage = location.pathname.includes('search');
    if (cur !== 'en' && !isSearchPage) {
      loadGoogleTranslate();
      document.body.style.opacity = '0';
      document.body.style.transition = 'opacity 0.15s ease';
      whenGtReady(() => {
        const sel = document.querySelector('.goog-te-combo');
        if (sel && sel.value !== cur) {
          sel.value = cur;
          sel.dispatchEvent(new Event('change'));
        }
        setTimeout(() => fadeBody('in'), 200);
      });
      setTimeout(() => fadeBody('in'), 5000);
    }

    const curLang = LANGS.find(l => l.code === cur) || LANGS[0];
    if (lbl) lbl.textContent = curLang.label;
    if (chipLabel) chipLabel.textContent = curLang.label;
    markActiveLang(curLang.code);

    // Desktop dropdown
    if (dd && dd.children.length === 0) buildDesktopDropdown(dd);

    let ddOpen = false;
    const openDD = () => {
      if (!dd || !btn || !chevron) return;
      const wrapRect = (document.getElementById('pwi-lang-wrap') || btn).getBoundingClientRect();
      dd.style.top = (wrapRect.bottom + 8) + 'px';
      dd.style.right = (window.innerWidth - wrapRect.right) + 'px';
      dd.style.display = 'block';
      btn.setAttribute('aria-expanded', 'true');
      chevron.style.transform = 'rotate(180deg)';
      ddOpen = true;
    };
    const closeDD = () => {
      if (!dd || !btn || !chevron) return;
      dd.style.display = 'none';
      btn.setAttribute('aria-expanded', 'false');
      chevron.style.transform = '';
      ddOpen = false;
    };

    if (btn) {
      btn.addEventListener('mouseenter', () => { btn.style.color = '#7C9DF7'; });
      btn.addEventListener('mouseleave', () => { if (!ddOpen) btn.style.color = '#cbd5e1'; });
      btn.addEventListener('click', e => { e.stopPropagation(); ddOpen ? closeDD() : openDD(); });
    }

    document.addEventListener('click', e => {
      const wrap = document.getElementById('pwi-lang-wrap');
      if (wrap && !wrap.contains(e.target)) closeDD();
    });

    // Desktop lang selection
    if (dd) {
      dd.addEventListener('click', e => {
        const opt = e.target.closest('[data-pwi-lang]');
        if (!opt) return;
        const code = opt.dataset.pwiLang;
        if (lbl) lbl.textContent = opt.dataset.pwiLabel;
        markActiveLang(code);
        closeDD();
        switchLang(code);
      });
    }

    // Mobile grid
    if (mobGrid && mobGrid.children.length === 0) {
      buildMobileGrid(mobGrid);
    }
    if (mobGrid) {
      mobGrid.addEventListener('click', e => {
        const opt = e.target.closest('[data-pwi-lang]');
        if (!opt) return;
        const code = opt.dataset.pwiLang;
        if (lbl) lbl.textContent = opt.dataset.pwiLabel;
        if (chipLabel) chipLabel.textContent = opt.dataset.pwiLabel;
        markActiveLang(code);
        closeMob(false);
        switchLang(code);
      });
    }
  }

  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', initPicker, { once: true });
  } else {
    initPicker();
  }
})();
